"""
generate_all_docs.py
Generates all 60 Wynn-branded .docx input documents for the executive skill library.
20 skills x 3 documents each = 60 total documents.
"""
"""
generate_all_docs.py  --  generates all 60 Wynn-branded .docx input documents.
Run from the executive-skills directory. Output goes to output/<persona>/<skill>/.
"""
import os, sys, urllib.request

UTILS_DIR = r"C:\Users\clwillia\.claude\skills\wynn-doc-format"
sys.path.insert(0, UTILS_DIR)
from wynn_doc_utils import (
    new_doc, set_margins, add_letterhead, add_meta_box,
    add_heading, add_body, add_bullet, add_markdown_table,
    add_footer, add_spacer,
)

LOGO_URL = "https://images.ctfassets.net/nmhu6zvnbnyf/6OGKMyj2vnB0ROqomayO0E/6e468d63e0f43d47b3c94c64e92ad1ee/image.png"
BASE_DIR = os.path.dirname(os.path.abspath(__file__))
_logo_cache = None

def get_logo():
    global _logo_cache
    if _logo_cache is None:
        try:
            with urllib.request.urlopen(LOGO_URL, timeout=10) as r:
                _logo_cache = r.read()
        except Exception:
            import base64
            _logo_cache = base64.b64decode(
                "iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwADhQGAWjR9awAAAABJRU5ErkJggg=="
            )
    return _logo_cache

def make_doc(title, dept, classification, meta_fields, sections, filename, out_dir, logo_bytes):
    doc = new_doc(); set_margins(doc)
    add_letterhead(doc, logo_bytes, title, department=dept, classification=classification)
    add_meta_box(doc, meta_fields)
    for sec in sections:
        add_heading(doc, sec["heading"], sec.get("level", 2))
        if sec.get("body"): add_body(doc, sec["body"])
        for b in sec.get("bullets", []): add_bullet(doc, b)
        if sec.get("table_header"):
            add_markdown_table(doc, sec["table_header"], sec.get("table_rows", []))
    add_footer(doc, filename)
    os.makedirs(out_dir, exist_ok=True)
    path = os.path.join(out_dir, filename)
    doc.save(path); print(f"  + {path}"); return path

DOC_COUNT = 0

def gen(title, dept, cls, meta, sections, filename, persona, slug):
    global DOC_COUNT
    out_dir = os.path.join(BASE_DIR, "output", persona, slug)
    make_doc(title, dept, cls, meta, sections, filename, out_dir, get_logo())
    DOC_COUNT += 1

